// amd/src/apiprovider.js
import $ from 'jquery';

export const init = () => {
    const providerSelector = $('select[name="s__quizaccess_aiquestiongenerator_apiprovider"]');
    const keyField = $('input[name="s__quizaccess_aiquestiongenerator_openai_key"]').closest('.form-group');
    const secretField = $('input[name="s__quizaccess_aiquestiongenerator_openai_secret"]').closest('.form-group');

    const updateVisibility = () => {
        const value = providerSelector.val();
        if (value === 'openai') {
            keyField.show();
            secretField.show();
        } else {
            keyField.hide();
            secretField.hide();
        }
    };

    // Trigger visibility check after a short delay to ensure DOM is ready.
    setTimeout(() => {
        updateVisibility();
        providerSelector.on('change', updateVisibility);
    }, 100);
};
